import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

import org.owasp.encoder.Encode;

public class SecureServlet extends HttpServlet {

    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {

        String userInput = request.getParameter("input");
        String sanitizedInput = Encode.forHtml(userInput); // Sanitize user input using OWASP Encoder

        response.setContentType("text/html");
        PrintWriter out = response.getWriter();

        out.println("<html>");
        out.println("<head><title>Secure Code</title></head>");
        out.println("<body>");
        out.println("<h1>User Input:</h1>");
        out.println("<p>" + sanitizedInput + "</p>"); // Output sanitized input
        out.println("</body>");
        out.println("</html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
